('f0000010-0000-0000-0000-000000000006','HOTEL','c0000003-0000-0000-0000-000000000021',4,'Charming historic property','Beautiful converted palazzo with original frescoes. Modern comforts blended with historic charm.',11,true,now()-INTERVAL '38 days',now()-INTERVAL '38 days'),
('f0000010-0000-0000-0000-000000000007','HOTEL','c0000003-0000-0000-0000-000000000022',5,'Magnifica ospitalita','Personale straordinario che parla piu lingue. Ci hanno aiutato a organizzare escursioni memorabili.',19,true,now()-INTERVAL '6 days',now()-INTERVAL '6 days'),
