('f0000010-0000-0000-0000-000000000024','HOTEL','c0000003-0000-0000-0000-000000000039',3,'Decent mid-range option','Nothing wrong but nothing memorable either. Serves its purpose for a transit stop.',6,true,now()-INTERVAL '52 days',now()-INTERVAL '52 days'),
