-- Restaurants 001-015, users 001-015
('f0000010-0000-0000-0000-000000000001','RESTAURANT','d0000004-0000-0000-0000-000000000001',5,'Migliore carbonara della mia vita','La pasta era perfetta al dente, il guanciale croccante, e la cremosita del tuorlo sublime. Da tornarci ogni settimana.',20,true,now()-INTERVAL '10 days',now()-INTERVAL '10 days'),
('f0000010-0000-0000-0000-000000000002','RESTAURANT','d0000004-0000-0000-0000-000000000002',4,'Excellent seafood','Fresh catch of the day was superb. The grilled octopus appetizer is a must-try. Wine list could be more varied.',14,true,now()-INTERVAL '18 days',now()-INTERVAL '18 days'),
('f0000010-0000-0000-0000-000000000003','RESTAURANT','d0000004-0000-0000-0000-000000000003',5,'A culinary masterpiece','Every course was a work of art. The tasting menu with wine pairing is worth the splurge. Book weeks in advance.',28,true,now()-INTERVAL '3 days',now()-INTERVAL '3 days'),
('f0000010-0000-0000-0000-000000000004','RESTAURANT','d0000004-0000-0000-0000-000000000004',3,'Buono ma servizio lento','Il cibo e buono, soprattutto gli antipasti. Pero abbiamo aspettato 45 minuti per i primi. Troppo.',5,true,now()-INTERVAL '40 days',now()-INTERVAL '40 days'),
('f0000010-0000-0000-0000-000000000005','RESTAURANT','d0000004-0000-0000-0000-000000000005',4,'Cozy family trattoria','Feels like eating at nonna''s house. Homemade pasta, generous portions, and the tiramisu is to die for.',16,true,now()-INTERVAL '15 days',now()-INTERVAL '15 days'),
('f0000010-0000-0000-0000-000000000006','RESTAURANT','d0000004-0000-0000-0000-000000000006',5,'Pizza napoletana perfetta','Il cornicione soffice, il pomodoro San Marzano, la mozzarella di bufala filante. Questa e la vera pizza.',25,true,now()-INTERVAL '6 days',now()-INTERVAL '6 days'),
('f0000010-0000-0000-0000-000000000007','RESTAURANT','d0000004-0000-0000-0000-000000000007',2,'Overrated tourist trap','Long wait, mediocre food, inflated prices. The pasta was overcooked and the sauce tasted like it came from a jar.',2,true,now()-INTERVAL '55 days',now()-INTERVAL '55 days'),
('f0000010-0000-0000-0000-000000000008','RESTAURANT','d0000004-0000-0000-0000-000000000008',4,'Hidden gem off the beaten path','Found this place on a side street and it was the best meal of our trip. Try the pappardelle al cinghiale.',12,true,now()-INTERVAL '22 days',now()-INTERVAL '22 days'),
('f0000010-0000-0000-0000-000000000009','RESTAURANT','d0000004-0000-0000-0000-000000000009',5,'Fine dining at its best','Impeccable presentation, bold flavors, and a sommelier who knows their craft. An unforgettable evening.',22,true,now()-INTERVAL '8 days',now()-INTERVAL '8 days'),
('f0000010-0000-0000-0000-000000000010','RESTAURANT','d0000004-0000-0000-0000-000000000010',3,'Carino ma porzioni piccole','Ambiente molto bello e curato. Piatti esteticamente perfetti ma le porzioni sono da aperitivo, non da cena.',6,true,now()-INTERVAL '35 days',now()-INTERVAL '35 days'),
('f0000010-0000-0000-0000-000000000011','RESTAURANT','d0000004-0000-0000-0000-000000000011',4,'Excellent wine selection','The food is good but the wine list is exceptional. The sommelier recommended a local Nero d''Avola that was divine.',10,true,now()-INTERVAL '28 days',now()-INTERVAL '28 days'),
('f0000010-0000-0000-0000-000000000012','RESTAURANT','d0000004-0000-0000-0000-000000000012',5,'Worth the detour','We drove 40 minutes out of our way based on a local''s recommendation and it was absolutely worth it.',19,true,now()-INTERVAL '11 days',now()-INTERVAL '11 days'),
('f0000010-0000-0000-0000-000000000013','RESTAURANT','d0000004-0000-0000-0000-000000000013',4,'Fantastica vista sul mare','Mangiare con quella vista e un privilegio. Il pesce e freschissimo. Prezzi un po alti ma giustificati dal contesto.',8,true,now()-INTERVAL '20 days',now()-INTERVAL '20 days'),
('f0000010-0000-0000-0000-000000000014','RESTAURANT','d0000004-0000-0000-0000-000000000014',2,'Non ci torneremo','Prenotazione non rispettata, ci hanno fatto aspettare 30 minuti in piedi. Cibo nella media. Scortesia al momento del conto.',1,false,now()-INTERVAL '68 days',now()-INTERVAL '68 days'),
('f0000010-0000-0000-0000-000000000015','RESTAURANT','d0000004-0000-0000-0000-000000000015',5,'Life-changing risotto','I have eaten risotto all over Italy and this is the benchmark. Creamy, perfectly seasoned, with saffron from their own garden.',30,true,now()-INTERVAL '5 days',now()-INTERVAL '5 days'),
-- Restaurants 016-035, users 001-020
('f0000010-0000-0000-0000-000000000001','RESTAURANT','d0000004-0000-0000-0000-000000000016',4,'Ottimi dolci fatti in casa','I dessert sono il punto forte. La torta della nonna e la panna cotta sono incredibili. Pranzo nella media.',11,true,now()-INTERVAL '32 days',now()-INTERVAL '32 days'),
('f0000010-0000-0000-0000-000000000002','RESTAURANT','d0000004-0000-0000-0000-000000000017',5,'Best meal in months','The hand-rolled pasta with truffle was ethereal. Intimate setting, knowledgeable staff, fair prices.',23,true,now()-INTERVAL '7 days',now()-INTERVAL '7 days'),
('f0000010-0000-0000-0000-000000000003','RESTAURANT','d0000004-0000-0000-0000-000000000018',3,'Good but not great','Solid cooking but lacking the wow factor. Decent for a weeknight dinner, would not plan a special occasion here.',4,true,now()-INTERVAL '45 days',now()-INTERVAL '45 days'),
('f0000010-0000-0000-0000-000000000004','RESTAURANT','d0000004-0000-0000-0000-000000000019',5,'Cucina della mamma','Piatti semplici ma preparati con amore e ingredienti di prima qualita. Come mangiare a casa della nonna.',18,true,now()-INTERVAL '12 days',now()-INTERVAL '12 days'),
('f0000010-0000-0000-0000-000000000005','RESTAURANT','d0000004-0000-0000-0000-000000000020',4,'Trendy spot, solid food','Instagram-worthy plating and the food actually tastes as good as it looks. Cocktails are creative too.',13,true,now()-INTERVAL '19 days',now()-INTERVAL '19 days'),
('f0000010-0000-0000-0000-000000000006','RESTAURANT','d0000004-0000-0000-0000-000000000021',5,'Exceptional tasting menu','Seven courses of pure joy. Each dish told a story about regional ingredients. The chef came to our table - so gracious.',27,true,now()-INTERVAL '4 days',now()-INTERVAL '4 days'),
('f0000010-0000-0000-0000-000000000007','RESTAURANT','d0000004-0000-0000-0000-000000000022',4,'Reliable neighborhood joint','We ate here three times during our week-long stay. Consistent quality, warm atmosphere, reasonable prices.',9,true,now()-INTERVAL '30 days',now()-INTERVAL '30 days'),
('f0000010-0000-0000-0000-000000000008','RESTAURANT','d0000004-0000-0000-0000-000000000023',3,'Atmosfera bella, cibo cosi cosi','Il locale e bellissimo con il giardino interno. Purtroppo la cucina non e allo stesso livello dell ambiente.',5,true,now()-INTERVAL '42 days',now()-INTERVAL '42 days'),
('f0000010-0000-0000-0000-000000000009','RESTAURANT','d0000004-0000-0000-0000-000000000024',5,'Unforgettable anniversary dinner','They arranged flowers at our table and a personalized dessert. The food matched the occasion perfectly.',21,true,now()-INTERVAL '9 days',now()-INTERVAL '9 days'),
('f0000010-0000-0000-0000-000000000010','RESTAURANT','d0000004-0000-0000-0000-000000000025',2,'Quantity over quality','Huge portions but everything tasted bland. The bruschetta was soggy and the pasta sauce was tasteless.',0,true,now()-INTERVAL '60 days',now()-INTERVAL '60 days'),
('f0000010-0000-0000-0000-000000000011','RESTAURANT','d0000004-0000-0000-0000-000000000026',4,'Lovely lunch spot','Perfect for a leisurely afternoon meal. The insalata caprese with burrata was heavenly. Good house wine.',7,true,now()-INTERVAL '25 days',now()-INTERVAL '25 days'),
('f0000010-0000-0000-0000-000000000012','RESTAURANT','d0000004-0000-0000-0000-000000000027',5,'Una scoperta incredibile','Piccolo locale con solo 8 tavoli. Il menu cambia ogni giorno in base al mercato. Poesia culinaria.',24,true,now()-INTERVAL '6 days',now()-INTERVAL '6 days'),
('f0000010-0000-0000-0000-000000000013','RESTAURANT','d0000004-0000-0000-0000-000000000028',4,'Great for groups','We were eight people and they accommodated us perfectly. Family-style sharing plates are the way to go here.',10,true,now()-INTERVAL '23 days',now()-INTERVAL '23 days'),
('f0000010-0000-0000-0000-000000000014','RESTAURANT','d0000004-0000-0000-0000-000000000029',3,'Hit or miss','Some dishes were excellent (the antipasti), others disappointing (overcooked fish). Inconsistent kitchen.',3,false,now()-INTERVAL '50 days',now()-INTERVAL '50 days'),
('f0000010-0000-0000-0000-000000000015','RESTAURANT','d0000004-0000-0000-0000-000000000030',5,'Michelin quality without the fuss','No pretension, just incredible food. The homemade ravioli with sage butter brought tears to my eyes.',26,true,now()-INTERVAL '2 days',now()-INTERVAL '2 days'),
-- Restaurants 031-055, users 016-030 + 001-010
('f0000010-0000-0000-0000-000000000016','RESTAURANT','d0000004-0000-0000-0000-000000000031',4,'Ottima enoteca con cucina','Selezione di vini eccezionale. I taglieri di salumi e formaggi sono generosi e di qualita. Perfetto per un aperitivo.',12,true,now()-INTERVAL '16 days',now()-INTERVAL '16 days'),
('f0000010-0000-0000-0000-000000000017','RESTAURANT','d0000004-0000-0000-0000-000000000032',5,'The pasta whisperer','I watched the chef make pasta by hand through the open kitchen. Every dish was a masterclass in simplicity.',20,true,now()-INTERVAL '8 days',now()-INTERVAL '8 days'),
('f0000010-0000-0000-0000-000000000018','RESTAURANT','d0000004-0000-0000-0000-000000000033',3,'Troppo affollato','Buon cibo ma impossibile avere una conversazione con quel livello di rumore. Tavoli troppo vicini.',4,true,now()-INTERVAL '38 days',now()-INTERVAL '38 days'),
('f0000010-0000-0000-0000-000000000019','RESTAURANT','d0000004-0000-0000-0000-000000000034',5,'Farm to table done right','Everything sourced within 30km. You can taste the freshness. The vegetable garden out back supplies half the menu.',22,true,now()-INTERVAL '10 days',now()-INTERVAL '10 days'),
('f0000010-0000-0000-0000-000000000020','RESTAURANT','d0000004-0000-0000-0000-000000000035',4,'Delightful brunch','Best brunch we had in Italy. Fresh juices, eggs benedict with prosciutto, and incredible pastries.',15,true,now()-INTERVAL '21 days',now()-INTERVAL '21 days'),
('f0000010-0000-0000-0000-000000000021','RESTAURANT','d0000004-0000-0000-0000-000000000036',2,'Non vale la fila','Due ore di attesa per un tavolo. Il cibo e buono ma non due-ore-di-fila buono. Servizio frettoloso.',1,true,now()-INTERVAL '65 days',now()-INTERVAL '65 days'),
('f0000010-0000-0000-0000-000000000022','RESTAURANT','d0000004-0000-0000-0000-000000000037',5,'Pure Italian joy','From the warm bread basket to the espresso, every moment was a celebration of Italian food culture.',25,true,now()-INTERVAL '5 days',now()-INTERVAL '5 days'),
('f0000010-0000-0000-0000-000000000023','RESTAURANT','d0000004-0000-0000-0000-000000000038',4,'Solid seafood restaurant','Fresh catches displayed on ice at the entrance. Grilled branzino was perfectly executed. Good value.',8,true,now()-INTERVAL '27 days',now()-INTERVAL '27 days'),
('f0000010-0000-0000-0000-000000000024','RESTAURANT','d0000004-0000-0000-0000-000000000039',3,'Interesting concept, uneven execution','Creative fusion menu but some combinations did not work. The sushi-pizza hybrid was a miss. Cocktails were great though.',6,true,now()-INTERVAL '43 days',now()-INTERVAL '43 days'),
('f0000010-0000-0000-0000-000000000025','RESTAURANT','d0000004-0000-0000-0000-000000000040',5,'Il miglior gelato artigianale','Non e un ristorante tradizionale ma il gelato e incredibile. Gusti unici come ricotta e fichi. Imperdibile.',17,true,now()-INTERVAL '3 days',now()-INTERVAL '3 days'),
('f0000010-0000-0000-0000-000000000026','RESTAURANT','d0000004-0000-0000-0000-000000000041',4,'Classic Italian done well','No reinventing the wheel here, just time-tested recipes executed with care. The lasagna is a standout.',11,true,now()-INTERVAL '17 days',now()-INTERVAL '17 days'),
('f0000010-0000-0000-0000-000000000027','RESTAURANT','d0000004-0000-0000-0000-000000000042',5,'Chef''s table experience was unforgettable','Watching the team work in perfect harmony while eating eight incredible courses. Highlight of our trip.',29,true,now()-INTERVAL '4 days',now()-INTERVAL '4 days'),
('f0000010-0000-0000-0000-000000000028','RESTAURANT','d0000004-0000-0000-0000-000000000043',3,'Bel posto, menu limitato','Location stupenda sulla piazza ma il menu e troppo ridotto. Solo 3 primi e 3 secondi. Qualita discreta.',5,true,now()-INTERVAL '36 days',now()-INTERVAL '36 days'),
('f0000010-0000-0000-0000-000000000029','RESTAURANT','d0000004-0000-0000-0000-000000000044',4,'Great vegetarian options','Finally an Italian restaurant that takes vegetarian food seriously. The eggplant parmigiana was incredible.',13,true,now()-INTERVAL '14 days',now()-INTERVAL '14 days'),
('f0000010-0000-0000-0000-000000000030','RESTAURANT','d0000004-0000-0000-0000-000000000045',5,'Perfection on a plate','The thinly sliced raw fish with citrus dressing was revelatory. Followed by the most tender ossobuco ever.',21,true,now()-INTERVAL '7 days',now()-INTERVAL '7 days'),
('f0000010-0000-0000-0000-000000000001','RESTAURANT','d0000004-0000-0000-0000-000000000046',4,'Aperitivo perfetto','Il buffet dell aperitivo e ricchissimo e con un Aperol Spritz a 8 euro e il miglior affare della citta.',9,true,now()-INTERVAL '29 days',now()-INTERVAL '29 days'),
('f0000010-0000-0000-0000-000000000002','RESTAURANT','d0000004-0000-0000-0000-000000000047',3,'Good not great','Tasty enough but not the transcendent experience reviews promised. Maybe we caught them on an off night.',3,true,now()-INTERVAL '48 days',now()-INTERVAL '48 days'),
('f0000010-0000-0000-0000-000000000003','RESTAURANT','d0000004-0000-0000-0000-000000000048',5,'A temple of gastronomy','This is not just dinner, it is a theatrical experience. The molecular gastronomy dessert was mind-blowing.',27,true,now()-INTERVAL '2 days',now()-INTERVAL '2 days'),
('f0000010-0000-0000-0000-000000000004','RESTAURANT','d0000004-0000-0000-0000-000000000049',4,'Warm and welcoming','The owner greeted us like old friends. Generous pours of wine and a complimentary limoncello to finish.',10,true,now()-INTERVAL '20 days',now()-INTERVAL '20 days'),
('f0000010-0000-0000-0000-000000000005','RESTAURANT','d0000004-0000-0000-0000-000000000050',2,'Style over substance','Beautiful interior but the food was bland and overpriced. The risotto was gummy and underseasoned.',0,false,now()-INTERVAL '58 days',now()-INTERVAL '58 days');

-- ===================== DESTINATION REVIEWS (~50) =====================
INSERT INTO reviews (user_id, target_type, target_id, rating, title, content, helpful_count, verified, created_at, updated_at)
SELECT uid, 'DESTINATION', did, rating, title, content, helpful, verified,
       now() - (random() * INTERVAL '180 days'), now() - (random() * INTERVAL '180 days')
FROM (VALUES
('f0000010-0000-0000-0000-000000000001'::uuid,(SELECT id FROM destinations ORDER BY name LIMIT 1 OFFSET 0),5,'Breathtaking beyond words','Every corner reveals a new postcard-worthy view. The local culture is warm and welcoming. A must-visit.',22,true),
('f0000010-0000-0000-0000-000000000002'::uuid,(SELECT id FROM destinations ORDER BY name LIMIT 1 OFFSET 1),4,'Great trip overall','Beautiful scenery and plenty to do. Public transport could be better but taxis are affordable.',14,true),
('f0000010-0000-0000-0000-000000000003'::uuid,(SELECT id FROM destinations ORDER BY name LIMIT 1 OFFSET 2),5,'Destinazione da sogno','Paesaggi mozzafiato, cibo eccellente, gente accogliente. Ci torneremo senza dubbio.',28,true),
('f0000010-0000-0000-0000-000000000004'::uuid,(SELECT id FROM destinations ORDER BY name LIMIT 1 OFFSET 3),3,'Beautiful but overcrowded','The destination itself is stunning but the crowds in summer are overwhelming. Visit in shoulder season.',6,true),
('f0000010-0000-0000-0000-000000000005'::uuid,(SELECT id FROM destinations ORDER BY name LIMIT 1 OFFSET 4),5,'Changed my perspective on travel','This place has a magical energy. The people, the food, the history - everything came together perfectly.',25,true),
('f0000010-0000-0000-0000-000000000006'::uuid,(SELECT id FROM destinations ORDER BY name LIMIT 1 OFFSET 5),4,'Un viaggio memorabile','Due settimane qui e non sono bastate. Ogni giorno una scoperta nuova. Consigliatissimo.',17,true),
('f0000010-0000-0000-0000-000000000007'::uuid,(SELECT id FROM destinations ORDER BY name LIMIT 1 OFFSET 6),2,'Not what I expected','The brochures made it look pristine but reality was different. Lots of construction and tourist traps.',3,true),
('f0000010-0000-0000-0000-000000000008'::uuid,(SELECT id FROM destinations ORDER BY name LIMIT 1 OFFSET 7),5,'Paradise on earth','Crystal clear waters, white sand beaches, and the most stunning sunsets. Heaven exists and it is here.',30,true),
('f0000010-0000-0000-0000-000000000009'::uuid,(SELECT id FROM destinations ORDER BY name LIMIT 1 OFFSET 8),4,'Rich history and culture','Every building tells a story. Museums are world-class. The walking tours are the best way to experience it.',12,true),
('f0000010-0000-0000-0000-000000000010'::uuid,(SELECT id FROM destinations ORDER BY name LIMIT 1 OFFSET 9),5,'Esperienza indimenticabile','La combinazione di natura, cultura e gastronomia rende questa destinazione unica al mondo.',20,true),
('f0000010-0000-0000-0000-000000000011'::uuid,(SELECT id FROM destinations ORDER BY name LIMIT 1 OFFSET 0),4,'Well worth the long flight','Despite the jet lag, the moment we arrived we knew it was special. So much to see and do.',15,true),
('f0000010-0000-0000-0000-000000000012'::uuid,(SELECT id FROM destinations ORDER BY name LIMIT 1 OFFSET 1),5,'Our happy place','This is our third visit and we discover something new every time. It feels like a second home now.',23,true),
('f0000010-0000-0000-0000-000000000013'::uuid,(SELECT id FROM destinations ORDER BY name LIMIT 1 OFFSET 2),3,'Bella ma costosa','Destinazione meravigliosa ma il costo della vita e molto alto. Budget almeno il doppio di quanto pensi.',7,true),
('f0000010-0000-0000-0000-000000000014'::uuid,(SELECT id FROM destinations ORDER BY name LIMIT 1 OFFSET 3),4,'Perfect for adventure seekers','Hiking, diving, kayaking - if you love outdoor activities this is your place. Infrastructure is good.',11,true),
('f0000010-0000-0000-0000-000000000015'::uuid,(SELECT id FROM destinations ORDER BY name LIMIT 1 OFFSET 4),5,'Magical at every season','We visited in winter expecting less, but the snow-capped mountains and cozy atmosphere were enchanting.',26,true),
('f0000010-0000-0000-0000-000000000016'::uuid,(SELECT id FROM destinations ORDER BY name LIMIT 1 OFFSET 5),5,'Ci ha rubato il cuore','Siamo partiti per una settimana e siamo rimasti un mese. La qualita della vita qui e straordinaria.',19,true),
('f0000010-0000-0000-0000-000000000017'::uuid,(SELECT id FROM destinations ORDER BY name LIMIT 1 OFFSET 6),4,'Underrated gem','Not on most tourist radars which is part of the charm. Authentic experiences around every corner.',13,true),
('f0000010-0000-0000-0000-000000000018'::uuid,(SELECT id FROM destinations ORDER BY name LIMIT 1 OFFSET 7),3,'Good but infrastructure needs work','Beautiful nature but roads are bad, internet is spotty, and finding accommodation can be challenging.',5,false),
('f0000010-0000-0000-0000-000000000019'::uuid,(SELECT id FROM destinations ORDER BY name LIMIT 1 OFFSET 8),5,'Once in a lifetime experience','The northern lights alone justified the trip. Add the hot springs and glacier walks and it is perfection.',24,true),
('f0000010-0000-0000-0000-000000000020'::uuid,(SELECT id FROM destinations ORDER BY name LIMIT 1 OFFSET 9),4,'Ottima per le famiglie','Tante attivita per i bambini, spiagge sicure, e ristoranti family-friendly. Vacanza perfetta.',16,true),
('f0000010-0000-0000-0000-000000000021'::uuid,(SELECT id FROM destinations ORDER BY name LIMIT 1 OFFSET 0),5,'Life-changing journey','Traveled solo and met incredible people. The local hospitality is unmatched. Already planning my return.',21,true),
('f0000010-0000-0000-0000-000000000022'::uuid,(SELECT id FROM destinations ORDER BY name LIMIT 1 OFFSET 1),3,'Peak season was a mistake','Beautiful destination ruined by massive crowds. Come off-season for the real experience.',4,true),
('f0000010-0000-0000-0000-000000000023'::uuid,(SELECT id FROM destinations ORDER BY name LIMIT 1 OFFSET 2),4,'Worth every penny','Yes, it is expensive. But the experiences you have here are priceless. Quality over quantity.',10,true),
('f0000010-0000-0000-0000-000000000024'::uuid,(SELECT id FROM destinations ORDER BY name LIMIT 1 OFFSET 3),5,'La perla del Mediterraneo','Acque cristalline, villaggi pittoreschi, cucina divina. Ogni giorno qui e un regalo.',27,true),
('f0000010-0000-0000-0000-000000000025'::uuid,(SELECT id FROM destinations ORDER BY name LIMIT 1 OFFSET 4),4,'So much to explore','Two weeks were not enough. The diversity of landscapes within such a small area is remarkable.',18,true),
('f0000010-0000-0000-0000-000000000026'::uuid,(SELECT id FROM destinations ORDER BY name LIMIT 1 OFFSET 5),5,'Best vacation ever','Everything exceeded expectations. The local guides were knowledgeable and passionate. Unforgettable.',29,true),
('f0000010-0000-0000-0000-000000000027'::uuid,(SELECT id FROM destinations ORDER BY name LIMIT 1 OFFSET 6),2,'Deludente rispetto alle aspettative','Troppo turistico, prezzi gonfiati, e la spiaggia era sporca. Forse siamo stati sfortunati.',2,true),
('f0000010-0000-0000-0000-000000000028'::uuid,(SELECT id FROM destinations ORDER BY name LIMIT 1 OFFSET 7),4,'Great food destination','Came for the food and was not disappointed. Every meal was an adventure. Night markets are incredible.',14,true),
('f0000010-0000-0000-0000-000000000029'::uuid,(SELECT id FROM destinations ORDER BY name LIMIT 1 OFFSET 8),5,'Spiritual and beautiful','Beyond the tourist sites, there is a spiritual depth to this place that touched our souls.',22,true),
('f0000010-0000-0000-0000-000000000030'::uuid,(SELECT id FROM destinations ORDER BY name LIMIT 1 OFFSET 9),4,'Il posto ideale per staccare','Niente WiFi? Nessun problema. Qui impari a rallentare e goderti il momento. Natura pura.',11,true),
('f0000010-0000-0000-0000-000000000001'::uuid,(SELECT id FROM destinations ORDER BY name LIMIT 1 OFFSET 10),5,'Absolutely spectacular','The landscapes here defy description. Photos do not do it justice. You have to see it to believe it.',20,true),
('f0000010-0000-0000-0000-000000000002'::uuid,(SELECT id FROM destinations ORDER BY name LIMIT 1 OFFSET 11),4,'Cultura ricchissima','Musei, teatri, architettura - ogni angolo racconta secoli di storia. Una destinazione per menti curiose.',16,true),
('f0000010-0000-0000-0000-000000000003'::uuid,(SELECT id FROM destinations ORDER BY name LIMIT 1 OFFSET 12),5,'Adventure paradise','Zip-lining through the canopy, snorkeling in cenotes, exploring ancient ruins - packed every day.',23,true),
('f0000010-0000-0000-0000-000000000004'::uuid,(SELECT id FROM destinations ORDER BY name LIMIT 1 OFFSET 13),3,'Nice but overhyped','Instagram made this place look like heaven. Reality is nice but not mind-blowing. Still worth a visit.',8,true),
('f0000010-0000-0000-0000-000000000005'::uuid,(SELECT id FROM destinations ORDER BY name LIMIT 1 OFFSET 14),4,'Perfect winter escape','Sun, warmth, and beautiful beaches when everything back home is gray and cold. Exactly what we needed.',13,true),
('f0000010-0000-0000-0000-000000000006'::uuid,(SELECT id FROM destinations ORDER BY name LIMIT 1 OFFSET 10),5,'Ritorno trionfale','Seconda visita e ancora meglio della prima. Abbiamo esplorato zone meno turistiche ed e stato magico.',19,true),
('f0000010-0000-0000-0000-000000000007'::uuid,(SELECT id FROM destinations ORDER BY name LIMIT 1 OFFSET 11),4,'Vibrant and energetic','The nightlife, street food, and music scene are incredible. Not for the faint-hearted but so alive.',15,true),
('f0000010-0000-0000-0000-000000000008'::uuid,(SELECT id FROM destinations ORDER BY name LIMIT 1 OFFSET 12),5,'Serenity achieved','Came here stressed, left completely recharged. The thermal baths and mountain air work wonders.',25,true),
('f0000010-0000-0000-0000-000000000009'::uuid,(SELECT id FROM destinations ORDER BY name LIMIT 1 OFFSET 13),3,'Language barrier was tough','Beautiful place but very few English speakers. Learn basic phrases before you go. Worth the effort though.',6,true),
('f0000010-0000-0000-0000-000000000010'::uuid,(SELECT id FROM destinations ORDER BY name LIMIT 1 OFFSET 14),4,'Gastronomia eccezionale','Ogni regione ha le sue specialita. Abbiamo fatto un tour gastronomico ed e stato il viaggio piu gustoso di sempre.',17,true),
('f0000010-0000-0000-0000-000000000011'::uuid,(SELECT id FROM destinations ORDER BY name LIMIT 1 OFFSET 10),5,'Solo travel perfection','Safe, friendly, easy to navigate. Met wonderful people at hostels and cafes. Already miss it.',21,true),
('f0000010-0000-0000-0000-000000000012'::uuid,(SELECT id FROM destinations ORDER BY name LIMIT 1 OFFSET 11),4,'Historical treasure trove','Ancient ruins, medieval towns, Renaissance art - a history lover''s dream come true.',12,true),
('f0000010-0000-0000-0000-000000000013'::uuid,(SELECT id FROM destinations ORDER BY name LIMIT 1 OFFSET 12),3,'Bene ma troppo caldo','Agosto non e il mese ideale. 40 gradi e umidita altissima. In primavera deve essere perfetto.',7,true),
('f0000010-0000-0000-0000-000000000014'::uuid,(SELECT id FROM destinations ORDER BY name LIMIT 1 OFFSET 13),5,'Nature at its most dramatic','Waterfalls, volcanoes, rainforests - nature shows off here like nowhere else on earth.',28,true),
('f0000010-0000-0000-0000-000000000015'::uuid,(SELECT id FROM destinations ORDER BY name LIMIT 1 OFFSET 14),4,'Charming and photogenic','Every street corner is a photo opportunity. The architecture, the colors, the light - simply beautiful.',14,true),
('f0000010-0000-0000-0000-000000000016'::uuid,(SELECT id FROM destinations ORDER BY name LIMIT 1 OFFSET 10),5,'Viaggio trasformativo','Questo posto ti cambia. Ritorni a casa con una prospettiva diversa sulla vita. Esperienza profonda.',24,true),
('f0000010-0000-0000-0000-000000000017'::uuid,(SELECT id FROM destinations ORDER BY name LIMIT 1 OFFSET 11),2,'Safety concerns','Beautiful but did not feel safe in certain areas at night. Had a minor incident with a pickpocket.',3,true),
('f0000010-0000-0000-0000-000000000018'::uuid,(SELECT id FROM destinations ORDER BY name LIMIT 1 OFFSET 12),4,'Great value destination','Your money goes far here. Luxury experiences at a fraction of the cost of Western Europe.',10,true),
('f0000010-0000-0000-0000-000000000019'::uuid,(SELECT id FROM destinations ORDER BY name LIMIT 1 OFFSET 13),5,'The trip of a lifetime','Bucket list destination and it delivered. Swimming with dolphins, hiking volcanoes, star gazing - incredible.',26,true),
('f0000010-0000-0000-0000-000000000020'::uuid,(SELECT id FROM destinations ORDER BY name LIMIT 1 OFFSET 14),5,'Semplicemente perfetto','Niente da aggiungere. Destinazione perfetta in ogni aspetto. Ci torneremo ogni anno.',18,true)
) AS t(uid, did, rating, title, content, helpful, verified);

-- ===================== CRUISE REVIEWS (~30) =====================
INSERT INTO reviews (user_id, target_type, target_id, rating, title, content, helpful_count, verified, created_at, updated_at)
SELECT uid, 'CRUISE', cid, rating, title, content, helpful, verified,
       now() - (random() * INTERVAL '180 days'), now() - (random() * INTERVAL '180 days')
FROM (VALUES
('f0000010-0000-0000-0000-000000000001'::uuid,(SELECT id FROM cruises ORDER BY created_at LIMIT 1 OFFSET 0),5,'Best cruise of our lives','From the embarkation champagne to the farewell dinner, every moment was curated to perfection. The cabin was spacious and the ocean views were mesmerizing.',24,true),
('f0000010-0000-0000-0000-000000000002'::uuid,(SELECT id FROM cruises ORDER BY created_at LIMIT 1 OFFSET 1),4,'Great value all-inclusive','The food was surprisingly good for a cruise. Entertainment every night was varied and fun. Only dock time felt rushed.',16,true),
('f0000010-0000-0000-0000-000000000003'::uuid,(SELECT id FROM cruises ORDER BY created_at LIMIT 1 OFFSET 2),5,'Crociera da sogno','Il Mediterraneo visto dalla nave e uno spettacolo. Personale gentilissimo e cucina eccellente. Gia prenotato la prossima.',28,true),
('f0000010-0000-0000-0000-000000000004'::uuid,(SELECT id FROM cruises ORDER BY created_at LIMIT 1 OFFSET 3),3,'Mixed experience','The ship itself is beautiful and well-maintained. However, excursions were overpriced and the buffet got repetitive after day 3.',7,true),
('f0000010-0000-0000-0000-000000000005'::uuid,(SELECT id FROM cruises ORDER BY created_at LIMIT 1 OFFSET 4),4,'Perfect for couples','Romantic dinners at the captain''s table, private balcony watching the sunset, spa days at sea. Highly recommend.',18,true),
('f0000010-0000-0000-0000-000000000006'::uuid,(SELECT id FROM cruises ORDER BY created_at LIMIT 1 OFFSET 0),4,'Seconda crociera con loro','Sempre un ottimo livello. Quest anno hanno rinnovato la spa e il teatro. Menu migliorato rispetto all anno scorso.',12,true),
('f0000010-0000-0000-0000-000000000007'::uuid,(SELECT id FROM cruises ORDER BY created_at LIMIT 1 OFFSET 1),5,'Exceeded every expectation','First cruise and now I am hooked. The midnight buffet, the shows, waking up in a new port every day - magical.',22,true),
('f0000010-0000-0000-0000-000000000008'::uuid,(SELECT id FROM cruises ORDER BY created_at LIMIT 1 OFFSET 2),2,'Seasickness ruined it','Not the cruise''s fault but the ship rocked more than expected. Medical team was helpful but I spent half the trip in bed.',4,false),
('f0000010-0000-0000-0000-000000000009'::uuid,(SELECT id FROM cruises ORDER BY created_at LIMIT 1 OFFSET 3),5,'Family cruise perfection','Kids club kept the children happy all day. Adults enjoyed the pool and cocktail bar. Win-win for everyone.',25,true),
('f0000010-0000-0000-0000-000000000010'::uuid,(SELECT id FROM cruises ORDER BY created_at LIMIT 1 OFFSET 4),4,'Itinerario fantastico','Ogni porto era una scoperta. Napoli, Barcellona, Marsiglia - ognuno con il suo fascino. Nave comoda e pulita.',15,true),
('f0000010-0000-0000-0000-000000000011'::uuid,(SELECT id FROM cruises ORDER BY created_at LIMIT 1 OFFSET 0),5,'The ship is a destination itself','With five restaurants, a theater, two pools, a gym, and a spa - you never run out of things to do even at sea.',20,true),
('f0000010-0000-0000-0000-000000000012'::uuid,(SELECT id FROM cruises ORDER BY created_at LIMIT 1 OFFSET 1),3,'Good but crowded','Peak season meant long lines at the buffet and packed pool decks. The formal dining was excellent though.',8,true),
('f0000010-0000-0000-0000-000000000013'::uuid,(SELECT id FROM cruises ORDER BY created_at LIMIT 1 OFFSET 2),4,'Wonderful Mediterranean itinerary','Each port stop was well-timed. The on-board lectures about upcoming destinations were a nice touch.',11,true),
('f0000010-0000-0000-0000-000000000014'::uuid,(SELECT id FROM cruises ORDER BY created_at LIMIT 1 OFFSET 3),5,'Esperienza di lusso totale','Suite con maggiordomo personale, ristorante esclusivo, escursioni private. Il top del top.',30,true),
('f0000010-0000-0000-0000-000000000015'::uuid,(SELECT id FROM cruises ORDER BY created_at LIMIT 1 OFFSET 4),4,'Smooth sailing','Our first cruise and we were impressed. Everything was well-organized. The formal nights were a highlight.',13,true),
('f0000010-0000-0000-0000-000000000016'::uuid,(SELECT id FROM cruises ORDER BY created_at LIMIT 1 OFFSET 0),3,'Troppe spese extra','Il prezzo base sembra buono ma poi paghi per tutto: bevande, WiFi, escursioni. Alla fine costa il doppio.',5,true),
('f0000010-0000-0000-0000-000000000017'::uuid,(SELECT id FROM cruises ORDER BY created_at LIMIT 1 OFFSET 1),5,'A floating five-star hotel','The suites are enormous, the service is impeccable, and the food rivals any top restaurant on land.',26,true),
('f0000010-0000-0000-0000-000000000018'::uuid,(SELECT id FROM cruises ORDER BY created_at LIMIT 1 OFFSET 2),4,'Great entertainment program','Live music, comedy shows, Broadway-style performances - never a dull evening on board.',9,true),
('f0000010-0000-0000-0000-000000000019'::uuid,(SELECT id FROM cruises ORDER BY created_at LIMIT 1 OFFSET 3),2,'Cabin was tiny','For the price we paid, the cabin was disappointingly small. Barely room for two suitcases. The balcony was a joke.',2,true),
('f0000010-0000-0000-0000-000000000020'::uuid,(SELECT id FROM cruises ORDER BY created_at LIMIT 1 OFFSET 4),5,'Vacanza perfetta senza stress','Niente valigie da fare e disfare, niente ristoranti da cercare. Ti svegli in un posto nuovo ogni mattina. Perfetto.',21,true),
('f0000010-0000-0000-0000-000000000021'::uuid,(SELECT id FROM cruises ORDER BY created_at LIMIT 1 OFFSET 0),5,'Honeymoon bliss','The crew decorated our cabin with rose petals and champagne. Every dinner was candlelit with ocean views. Pure romance.',27,true),
('f0000010-0000-0000-0000-000000000022'::uuid,(SELECT id FROM cruises ORDER BY created_at LIMIT 1 OFFSET 1),4,'Well-organized shore excursions','Unlike other cruise lines, the excursions here were thoughtful and not just tourist traps. Guides were excellent.',14,true),
('f0000010-0000-0000-0000-000000000023'::uuid,(SELECT id FROM cruises ORDER BY created_at LIMIT 1 OFFSET 2),3,'Cibo buono ma ripetitivo','I primi tre giorni erano fantastici. Poi il menu ha cominciato a ripetersi. Ristorante a la carte ottimo pero.',6,true),
('f0000010-0000-0000-0000-000000000024'::uuid,(SELECT id FROM cruises ORDER BY created_at LIMIT 1 OFFSET 3),5,'Worth every penny','Splurged on a balcony suite and it transformed the experience. Watching dolphins from your private balcony is priceless.',23,true),
('f0000010-0000-0000-0000-000000000025'::uuid,(SELECT id FROM cruises ORDER BY created_at LIMIT 1 OFFSET 4),4,'Fun for all ages','Grandparents, parents, and grandkids all had an amazing time. Activities for every generation. Smart family vacation.',17,true),
('f0000010-0000-0000-0000-000000000026'::uuid,(SELECT id FROM cruises ORDER BY created_at LIMIT 1 OFFSET 0),4,'Terza crociera, sempre soddisfatti','Ormai siamo clienti fedeli. Il programma fedelta da vantaggi reali: upgrade gratuito e credito a bordo.',10,true),
('f0000010-0000-0000-0000-000000000027'::uuid,(SELECT id FROM cruises ORDER BY created_at LIMIT 1 OFFSET 1),5,'The sunset sail was unforgettable','Standing on deck as we sailed past the coast at golden hour with live jazz playing - pure cinema.',19,true),
('f0000010-0000-0000-0000-000000000028'::uuid,(SELECT id FROM cruises ORDER BY created_at LIMIT 1 OFFSET 2),3,'Not bad for first-timers','Good introduction to cruising. Ship was clean, food was decent, ports were interesting. Would try a luxury line next.',7,true),
('f0000010-0000-0000-0000-000000000029'::uuid,(SELECT id FROM cruises ORDER BY created_at LIMIT 1 OFFSET 3),4,'Relaxing and rejuvenating','The sea days were actually our favorites. Spa treatments, reading on deck, gourmet meals - pure relaxation.',12,true),
('f0000010-0000-0000-0000-000000000030'::uuid,(SELECT id FROM cruises ORDER BY created_at LIMIT 1 OFFSET 4),5,'Non vedo l ora di ripartire','Appena sbarcati abbiamo gia prenotato la prossima. Dipendenza da crociera e una cosa reale. Consigliatissimo.',22,true)
